export const ASSET_CATEGORIES: readonly string[] = [
  "biome",
  "chars",
  "creatures",
  "dungeon",
  "foliage",
  "props",
  "quest",
  "resources",
  "tools",
  "weapons"
];

const BY_ID = new Map(ASSET_CATALOG.map((a) => [a.id, a]));
export function assetById(id: string): AssetEntry | undefined {
  return BY_ID.get(id);
}
